SELECT COUNT(1) > 0
FROM user_data_scopes
WHERE user_id = #{userId}
  AND scope_type = #{scopeType}
  AND scope_id = #{scopeId}
  AND deleted = 0

SELECT scope_id
FROM user_data_scopes
WHERE user_id = #{userId}
  AND scope_type = #{scopeType}
  AND deleted = 0

SELECT DISTINCT g.id FROM grades g WHERE g.deleted = 0 AND (
EXISTS ( SELECT 1 FROM user_data_scopes uds WHERE uds.scope_type = 'GRADE' AND uds.scope_id = g.id AND uds.user_id = #{userId} AND uds.deleted = 0 )
)

